// Иммутабельное состояние экрана
data class NewsState(
    val isLoading: Boolean = false,
    val news: List<NewsItem> = emptyList(),
    val error: String? = null,
    val selectedCategory: String = "all",
    val searchQuery: String = ""
) {
    // Валидные производные свойства
    val filteredNews: List<NewsItem>
        get() = news.filter { 
            (selectedCategory == "all" || it.category == selectedCategory) &&
            (searchQuery.isEmpty() || it.title.contains(searchQuery, true))
        }

    val isEmpty: Boolean
        get() = news.isEmpty() && !isLoading && error == null
}

// Все возможные действия пользователя
sealed class NewsIntent {
    object LoadNews : NewsIntent()
    data class SearchNews(val query: String) : NewsIntent()
    data class SelectCategory(val category: String) : NewsIntent()
    data class ToggleFavorite(val newsId: String) : NewsIntent()
    object Refresh : NewsIntent()
    object Retry : NewsIntent()
    object ClearError : NewsIntent()
}

// В Compose
@Composable
fun NewsScreen(viewModel: NewsViewModel) {
    val state by viewModel.state.collectAsState()

    NewsContent(
        state = state,
        onIntent = viewModel::processIntent
    )
}

@Composable
fun NewsContent(
    state: NewsState,
    onIntent: (NewsIntent) -> Unit
) {
    Column {
        // Search
        SearchBar(
            query = state.searchQuery,
            onQueryChange = { onIntent(NewsIntent.SearchNews(it)) }
        )

        // Categories
        CategoryChips(
            selected = state.selectedCategory,
            onSelect = { onIntent(NewsIntent.SelectCategory(it)) }
        )

        // Content based on state
        when {
            state.isLoading -> LoadingIndicator()
            state.error != null -> ErrorView(
                error = state.error,
                onRetry = { onIntent(NewsIntent.Retry) }
            )
            state.isEmpty -> EmptyState()
            else -> NewsList(
                news = state.filteredNews,
                onToggleFavorite = { onIntent(NewsIntent.ToggleFavorite(it)) }
            )
        }
    }
}
